// src/components/Common/OwnerCard.js
import React, { useState } from "react";

export default function OwnerCard({ owner, isManager = false, onClaimRestaurant }) {
  const [isClaimed, setIsClaimed] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const handleClaimClick = () => {
    if (!isManager) {
      alert("⚠️ Seul un manager peut attribuer un restaurant à un propriétaire.");
      return;
    }
    setShowConfirm(true);
  };

  const confirmClaim = () => {
    setIsClaimed(true);
    setShowConfirm(false);
    if (onClaimRestaurant) {
      onClaimRestaurant(owner);
    }
    alert(`✅ Le restaurant est maintenant attribué à ${owner.name} !`);
  };

  const styles = `
    .owner-card-simple {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 20px;
      padding: 20px;
      border: 1px solid rgba(34, 197, 94, 0.3);
      transition: all 0.3s ease;
      cursor: pointer;
    }
    
    .owner-card-simple:hover {
      transform: translateY(-5px);
      border-color: #22c55e;
      box-shadow: 0 10px 30px rgba(34, 197, 94, 0.2);
    }
    
    .owner-card-simple.claimed {
      border-color: #22c55e;
      background: linear-gradient(135deg, #1a3a2a, #0d2b1a);
    }
    
    .owner-header {
      display: flex;
      align-items: center;
      gap: 15px;
      margin-bottom: 15px;
    }
    
    .owner-avatar {
      width: 70px;
      height: 70px;
      border-radius: 50%;
      object-fit: cover;
      border: 3px solid #22c55e;
    }
    
    .owner-info {
      flex: 1;
    }
    
    .owner-name {
      font-size: 1.2rem;
      font-weight: bold;
      color: white;
      margin: 0 0 5px;
    }
    
    .owner-location {
      font-size: 0.8rem;
      color: #22c55e;
      display: flex;
      align-items: center;
      gap: 5px;
    }
    
    .owner-description {
      font-size: 0.85rem;
      color: rgba(255,255,255,0.7);
      line-height: 1.4;
      margin-bottom: 15px;
    }
    
    .claim-btn {
      width: 100%;
      padding: 10px;
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
      font-size: 0.9rem;
    }
    
    .claim-btn:hover:not(:disabled) {
      transform: scale(1.02);
      box-shadow: 0 5px 15px rgba(34, 197, 94, 0.4);
    }
    
    .claim-btn:disabled {
      background: #2d5a3a;
      cursor: not-allowed;
      opacity: 0.7;
    }
    
    .claimed-badge {
      display: inline-block;
      background: #22c55e;
      color: white;
      font-size: 0.7rem;
      padding: 3px 10px;
      border-radius: 20px;
      margin-top: 8px;
    }
    
    /* Modal de confirmation */
    .confirm-modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0,0,0,0.95);
      backdrop-filter: blur(8px);
      z-index: 10000;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    
    .confirm-modal {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 20px;
      padding: 25px;
      max-width: 400px;
      width: 90%;
      border: 2px solid #22c55e;
      text-align: center;
    }
    
    .confirm-title {
      color: white;
      font-size: 1.3rem;
      margin-bottom: 15px;
    }
    
    .confirm-text {
      color: rgba(255,255,255,0.7);
      margin-bottom: 20px;
      line-height: 1.5;
    }
    
    .confirm-buttons {
      display: flex;
      gap: 15px;
      justify-content: center;
    }
    
    .confirm-yes {
      background: #22c55e;
      border: none;
      padding: 10px 25px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
    }
    
    .confirm-no {
      background: #ef4444;
      border: none;
      padding: 10px 25px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
    }
    
    @media (max-width: 480px) {
      .owner-header {
        flex-direction: column;
        text-align: center;
      }
      
      .owner-name {
        font-size: 1rem;
      }
    }
  `;

  return (
    <>
      <style>{styles}</style>
      
      <div className={`owner-card-simple ${isClaimed ? 'claimed' : ''}`}>
        <div className="owner-header">
          <img src={owner.image} alt={owner.name} className="owner-avatar" />
          <div className="owner-info">
            <h3 className="owner-name">{owner.name}</h3>
            <div className="owner-location">
              <span>📍</span> {owner.location}
            </div>
          </div>
        </div>
        
        <p className="owner-description">
          {owner.bio.length > 100 ? owner.bio.substring(0, 100) + "..." : owner.bio}
        </p>
        
        {isClaimed ? (
          <div className="claimed-badge">✅ Restaurant attribué</div>
        ) : (
          <button 
            className="claim-btn" 
            onClick={handleClaimClick}
            disabled={!isManager}
          >
            🏪 C'est mon restaurant
          </button>
        )}
      </div>
      
      {/* Modal de confirmation */}
      {showConfirm && (
        <div className="confirm-modal-overlay" onClick={() => setShowConfirm(false)}>
          <div className="confirm-modal" onClick={(e) => e.stopPropagation()}>
            <h3 className="confirm-title">🏪 Attribution du restaurant</h3>
            <p className="confirm-text">
              Êtes-vous sûr de vouloir attribuer votre restaurant à <strong>{owner.name}</strong> ?<br/>
              Cette action rendra {owner.name} propriétaire officiel de l'établissement.
            </p>
            <div className="confirm-buttons">
              <button className="confirm-yes" onClick={confirmClaim}>✅ Oui, attribuer</button>
              <button className="confirm-no" onClick={() => setShowConfirm(false)}>❌ Annuler</button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
